import React, { useState, useEffect } from 'react';

interface Todo {
  id: string;
  text: string;
  completed: boolean;
}

const TodoList: React.FC = () => {
  const [todos, setTodos] = useState<Todo[]>([]);
  const [inputValue, setInputValue] = useState<string>('');

  // Load from localStorage on mount
  useEffect(() => {
    const savedTodos = localStorage.getItem('todos');
    if (savedTodos) setTodos(JSON.parse(savedTodos));
  }, []);

  // Save to localStorage whenever todos change
  useEffect(() => {
    localStorage.setItem('todos', JSON.stringify(todos));
  }, [todos]);

  const handleAddTodo = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim()) return;

    const newTodo: Todo = {
      id: crypto.randomUUID(),
      text: inputValue.trim(),
      completed: false,
    };

    setTodos([...todos, newTodo]);
    setInputValue('');
  };

  const toggleComplete = (id: string) => {
    setTodos(todos.map(todo => 
      todo.id === id ? { ...todo, completed: !todo.completed } : todo
    ));
  };

  const deleteTodo = (id: string) => {
    setTodos(todos.filter(todo => todo.id !== id));
  };

  return (
    <div style={{ maxWidth: '400px', margin: '2rem auto', fontFamily: 'sans-serif' }}>
      <h2>Todo List</h2>
      <form onSubmit={handleAddTodo} style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
        <input
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder="What needs to be done?"
          style={{ flex: 1, padding: '0.5rem' }}
        />
        <button type="submit" style={{ padding: '0.5rem 1rem' }}>Add</button>
      </form>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {todos.map(todo => (
          <li key={todo.id} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
            <input
              type="checkbox"
              checked={todo.completed}
              onChange={() => toggleComplete(todo.id)}
            />
            <span style={{ flex: 1, textDecoration: todo.completed ? 'line-through' : 'none' }}>
              {todo.text}
            </span>
            <button onClick={() => deleteTodo(todo.id)} style={{ color: '#d9534f', cursor: 'pointer' }}>
              Delete
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default TodoList;

import jwt
from typing import Dict, Any, List
from dataclasses import dataclass

SECRET_KEY = "your_secure_environment_variable_key"
ALGORITHM = "HS256"

@dataclass
class User:
    user_id: str
    email: str
    roles: List[str]

class AuthError(Exception):
    """Base exception for authentication failures"""
    pass

def validate_jwt_token(token: str) -> User:
    """
    Validates a JWT token and returns a User dataclass object.
    Handles expiration, signature integrity, and payload structure.
    """
    try:
        # jwt.decode automatically validates the signature and expiration (exp claim)
        payload: Dict[str, Any] = jwt.decode(
            token, 
            SECRET_KEY, 
            algorithms=[ALGORITHM]
        )

        # Extract user data
        user_id = payload.get("user_id")
        email = payload.get("email")
        roles = payload.get("roles", [])

        if not user_id or not email:
            raise AuthError("Malformed token: missing required 'user_id' or 'email' fields.")

        return User(user_id=user_id, email=email, roles=roles)

    except jwt.ExpiredSignatureError:
        raise AuthError("Token has expired.")
    except jwt.InvalidSignatureError:
        raise AuthError("Invalid token signature.")
    except jwt.DecodeError:
        raise AuthError("Malformed token payload.")
    except Exception as e:
        raise AuthError(f"Authentication failed: {str(e)}")
